<template>
    <div class="app-recent-product">
        <div class="product-filter-title m-b-25">
            <span>Recent Viewed Product</span>
        </div>
        <transition>
            <div class="app-recent-product-loading" v-if="isLoading" key="is-loading">
                <i class="icon-loading"></i>
            </div>
            <div v-else key="is-loaded">
                <list-products :products="products" col="col m-b-30" ></list-products>
            </div>
        </transition>
        
    </div>
</template>

<script>
    import {mapActions} from 'vuex'
    import ListProducts from '../partials/list-products'

    export default {
        name: "recent-product",
        components: {
            ListProducts
        },
        props :{
            numberOfRender : {
                type : Number,
                default : 5
            }
        },
        mounted: function () {
            let ids = this.getLocalStore('lr')
            if (ids.length >= this.numberOfRender)  {
                let temp = []
                for (let i = 0; i < this.numberOfRender; i++) {
                    temp.push(ids.pop())
                }
                ids = temp
            }
            this.isLoading = true
            this.getRecentProduct(ids).then( (res) => {
                let { status , data} = res.data
                this.isLoading = false
                if( status ){
                    this.products = data
                }
                
            })
        },
        data() {
            return {
                products: [],
                isLoading : false,
            }
        },
        methods: {
            ...mapActions({
                getRecentProduct: "$_Home/GET_RECENT_PRODUCT"
            }),
        }
    }
</script>

<style lang="scss" scoped>
    @import 'src/assets/style';
    .app-recent-product{
        &-loading{
            .icon-loading{
                background: $yellow;
            }
        }
    }
</style>
